select * from nursing_operation_record

    module = #{module}
    and record_type = #{recordType}
    and name like concat('%', #{name}, '%')
    and code like concat('%', #{code}, '%')
    and status = #{status}
    and elder_name like concat('%', #{elderName}, '%')
    and id_card like concat('%', #{idCard}, '%')
    and phone like concat('%', #{phone}, '%')
    and location like concat('%', #{location}, '%')
    and product_name = #{productName}

        and create_time >= #{params.beginTime}


        and create_time <= concat(#{params.endTime}, ' 23:59:59')


order by create_time desc, id desc

mapper.update:
update nursing_operation_record
set status = #{status}, update_by = #{username}, update_time = sysdate()
where module = #{module} and id = #{id}
